Bash(MSYS_NO_PATHCONV=1 docker exec bileraoracle-backend-1 node -e "
const oracledb = require\('oracledb'\);
\(async \(\) => {
  const conn = await oracledb.getConnection\({
    user: 'bilera', password: 'bilera',
    connectString: 'db:1521/FREEPDB1'
  }\);
  const stmts = [
    \\`CREATE TABLE contacts \(
      id VARCHAR2\(36\) DEFAULT SYS_GUID\(\) PRIMARY KEY,
      tenant_id NUMBER NOT NULL REFERENCES tenants\(id\),
      name VARCHAR2\(300\) NOT NULL,
      phone VARCHAR2\(100\),
      email VARCHAR2\(255\),
      web VARCHAR2\(500\),
      category VARCHAR2\(100\),
      notes CLOB,
      created_by VARCHAR2\(36\) NOT NULL REFERENCES users\(id\),
      created_at TIMESTAMP DEFAULT SYSTIMESTAMP,
      updated_at TIMESTAMP DEFAULT SYSTIMESTAMP
    \)\\`,
    \\`CREATE INDEX idx_contacts_tenant ON contacts\(tenant_id\)\\`,
    \\`CREATE INDEX idx_contacts_category ON contacts\(tenant_id, category\)\\`,
    \\`CREATE TABLE activity_contacts \(
      activity_id VARCHAR2\(36\) NOT NULL REFERENCES activities\(id\) ON DELETE CASCADE,
      contact_id VARCHAR2\(36\) NOT NULL REFERENCES contacts\(id\) ON DELETE CASCADE,
      role VARCHAR2\(100\),
      PRIMARY KEY \(activity_id, contact_id\)
    \)\\`,
  ];
  for \(const s of stmts\) {
    try { await conn.execute\(s\); console.log\('OK:', s.substring\(0,50\)\); }
    catch\(e\) {
      if \(e.errorNum === 955\) console.log\('Already exists:', s.substring\(0,50\)\);
      else console.error\('Error:', e.message\);
    }
  }
  // VPD policy
  try {
    await conn.execute\(\\`BEGIN
      DBMS_RLS.ADD_POLICY\(
        object_schema => USER,
        object_name => 'CONTACTS',
        policy_name => 'contacts_tenant_vpd',
        function_schema => USER,
        policy_function => 'VPD_TENANT_POLICY',
        statement_types => 'SELECT,UPDATE,DELETE'
      \);
    END;\\`\);
    console.log\('OK: VPD policy added'\);
  } catch\(e\) {
    if \(e.message.includes\('already exists'\)\) console.log\('VPD policy already exists'\);
    else console.error\('VPD Error:', e.message\);
  }
  await conn.commit\(\);
  await conn.close\(\);
  console.log\('Done'\);
}\)\(\);
" 2>&1)

